class Node {
    public int Value;
    public Node Next, Prev;  // dois ponteiros!
    public Node(int value) { Value = value; }
}

// Inserção no início — O(1)
void InsertBegin(ref Node head, ref Node tail, int value) {
    Node n = new Node(value);
    n.Next = head;
    if (head != null) head.Prev = n;  // antigo HEAD ganha predecessor
    else tail = n;                     // lista estava vazia
    head = n;
}

