type Node struct {
	Value int
	Next  *Node
	Prev  *Node
}

func insertBegin(head, tail **Node, value int) {
	n := &Node{Value: value}
	n.Next = *head
	if *head != nil {
		(*head).Prev = n // antigo HEAD ganha predecessor
	} else {
		*tail = n
	}
	*head = n
}

