    def __init__(self, value):
        self.value = value
        self.next = None
        self.prev = None  # ponteiro extra!

class DoublyLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None

    def insert_end(self, value):  # O(1) graças ao TAIL
        n = Node(value)
        if self.tail:
            n.prev = self.tail
            self.tail.next = n
        else:
            self.head = n
        self.tail = n

