class Node {
    constructor(value) {
        this.value = value;
        this.next = null;
        this.prev = null;  // ponteiro extra!
    }
}

class DoublyLinkedList {
    constructor() { this.head = null; this.tail = null; }

    insertEnd(value) {  // O(1) graças ao TAIL
        const n = new Node(value);
        if (this.tail) {
            n.prev = this.tail;
            this.tail.next = n;
        } else {
            this.head = n;
        }
        this.tail = n;
    }
}
